import{_ as t,o,c as d,ag as r}from"./chunks/framework.HG0H2VLS.js";const g=JSON.parse('{"title":"FilterBarV1 — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/patterns/FilterBarV1/FilterBarV1.figma-notes.md","filePath":"public/demos/src/patterns/FilterBarV1/FilterBarV1.figma-notes.md"}'),i={name:"public/demos/src/patterns/FilterBarV1/FilterBarV1.figma-notes.md"};function a(s,e,c,n,l,h){return o(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="filterbarv1-—-figma-notes" tabindex="-1">FilterBarV1 — Figma Notes <a class="header-anchor" href="#filterbarv1-—-figma-notes" aria-label="Permalink to &quot;FilterBarV1 — Figma Notes&quot;">​</a></h1><h2 id="figma-node" tabindex="-1">Figma Node <a class="header-anchor" href="#figma-node" aria-label="Permalink to &quot;Figma Node&quot;">​</a></h2><ul><li><strong>File:</strong> <code>Lus07xi8pPXLN87sQIyrEt</code> (Affino AI Design System)</li><li><strong>Component set:</strong> <code>2975:2303</code> (&quot;Filters V1&quot;)</li><li><strong>Tier:</strong> <code>Pattern</code> → <code>src/patterns/FilterBarV1/</code></li><li>URL: <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2975-2303" target="_blank" rel="noreferrer">https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2975-2303</a></li></ul><p>A/B variant <strong>1</strong> of the filter toolbar (see <a href="./../FilterBarV2/">FilterBarV2</a> for variant 2). Single-row bar: a saved-views control + a wrapping row of filter chips, with a search icon and kebab on the right.</p><h2 id="variant-matrix-9-type-×-desktop-mobile-dropdowns" tabindex="-1">Variant matrix (9 Type × Desktop/Mobile, + Dropdowns) <a class="header-anchor" href="#variant-matrix-9-type-×-desktop-mobile-dropdowns" aria-label="Permalink to &quot;Variant matrix (9 Type × Desktop/Mobile, + Dropdowns)&quot;">​</a></h2><p><code>Type</code> is a set of <strong>scenarios/states of one toolbar</strong>, not separate components — so they&#39;re modelled as JS modes + composed-component states, not 15 CSS variants.</p><table tabindex="0"><thead><tr><th>Node ID (Desktop / Mobile)</th><th>Type</th><th>How it&#39;s represented</th></tr></thead><tbody><tr><td>2975:2302 / 2975:2301</td><td>Default</td><td>base markup (empty/dashed chips)</td></tr><tr><td>2975:2292 / 2975:2298</td><td>Filter active</td><td>a chip carries <code>.filter-item--selected</code></td></tr><tr><td>2975:2291 / 2975:2297</td><td>View Dropdown</td><td>saved-views <code>.dropdown</code> is <code>.is-open</code></td></tr><tr><td>2975:2293 / 2975:2295</td><td>New View</td><td>root <code>.filter-bar-v1--new-view</code> (Input + Create)</td></tr><tr><td>2975:2290 / 2975:2299</td><td>Wrapping</td><td>more chips → <code>.filter-bar-v1__chips</code> flex-wraps</td></tr><tr><td>2989:6303 / 2989:6315</td><td>Save View</td><td>root <code>.filter-bar-v1--save-view</code> reveals a &quot;Save view&quot; primary CTA (Button, sm) in the chip flow after &quot;Add Filters&quot;</td></tr><tr><td>2975:2289 / 2975:2294</td><td>Search</td><td>root <code>.filter-bar-v1--search</code> (back + full-width Input)</td></tr><tr><td>2975:2300 / 2975:2296</td><td>Actions</td><td>kebab <code>.dropdown</code> is <code>.is-open</code> (Export / Generate Shipping Labels)</td></tr><tr><td>— / 2975:2288</td><td>Dropdowns (mobile)</td><td>the saved-views/actions menus as rendered on mobile</td></tr></tbody></table><p>Desktop fetched in full: Default, New View, Search; Mobile Default. The remaining are state/content permutations of those structures (verified against the parent-frame screenshot).</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li><strong>Desktop:</strong> single row <code>[views | chips ........ search-icon kebab]</code>. Shell gap <code>--ai-spacing-5</code> (16px) between the main group and the actions; the chip group sits behind a left divider (<code>border-left</code> + <code>padding-left: --ai-spacing-3</code>).</li><li><strong>Mobile (≤767px):</strong> <code>__main</code> becomes <code>display: contents</code> so views + chips promote to the outer flex; views + actions share row 1 (actions <code>margin-left: auto</code>), chips wrap to row 2 (<code>flex-basis: 100%</code>). Outer gap drops to <code>--ai-spacing-4</code> (12px) per Figma mobile.</li></ul><h2 id="modes-js-—-filterbarv1-js" tabindex="-1">Modes (JS — FilterBarV1.js) <a class="header-anchor" href="#modes-js-—-filterbarv1-js" aria-label="Permalink to &quot;Modes (JS — FilterBarV1.js)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Class</th><th>Entered by</th><th>Effect</th></tr></thead><tbody><tr><td>Search</td><td><code>.filter-bar-v1--search</code></td><td>🔍 (<code>data-filter-action=&quot;search&quot;</code>)</td><td>back-arrow + full-width search Input replace the bar; ← exits</td></tr><tr><td>New View</td><td><code>.filter-bar-v1--new-view</code></td><td>&quot;+ New view&quot; in saved-views menu (<code>data-filter-action=&quot;new-view&quot;</code>)</td><td>views trigger → &quot;New view&quot; Input + Create Button; chips collapse to only the <code>.filter-bar-v1__add</code> (&quot;Add Filters&quot;) chip (matches Figma New View). <strong>Create</strong> (<code>new-view-create</code>) appends the typed name as a new saved-view row (<code>addView</code>, flagged <code>data-view-empty=&quot;1&quot;</code>), selects it (<code>selectView</code> → trigger label + tick), and re-wires the new row&#39;s … menu (<code>Dropdown.initAll</code>); <strong>×</strong> (<code>new-view-exit</code>) cancels; empty name → just exits. A new (empty) view shows <strong>only the &quot;Add Filters&quot; chip</strong> via the <code>.filter-bar-v1--view-empty</code> class (non-destructive — chips stay in the DOM, hidden by CSS). Existing views keep their default chips; <code>selectView</code> toggles <code>--view-empty</code> from the row&#39;s <code>data-view-empty</code> flag, so switching back to All Orders / My Content restores the full chip set.</td></tr><tr><td>Save View</td><td><code>.filter-bar-v1--save-view</code></td><td>a filter added/amended — <strong>mock</strong>: clicking the &quot;Add Filters&quot; chip (FilterItem bubbles <code>filter-item:toggle</code> with <code>open:true</code>)</td><td>reveals the <code>.filter-bar-v1__save</code> &quot;Save view&quot; CTA (Button <code>--primary --sm</code>) in the chip flow, right after &quot;Add Filters&quot;. Clicking it (<code>data-filter-action=&quot;save-view&quot;</code>) is a mock &quot;save&quot; — drops the class and closes the Add Filters chip. <strong>TODO(backend:Filters)</strong> — the real trigger is a persisted filter-set change.</td></tr></tbody></table><p>The saved-views dropdown, kebab actions menu, per-row Copy/Delete mini-menu, and chip open/clear are owned by the <strong>Dropdown</strong> and <strong>FilterItem</strong> components (their own JS auto-binds).</p><p><strong>Saved-view selection + rename</strong> is wired by <code>FilterBarV1.js</code> (<code>wireViews</code>):</p><ul><li><strong>Single click</strong> a <code>menuitemradio</code> row → select: updates the trigger&#39;s <code>.filter-bar-v1__views-label</code>, flips <code>aria-checked</code>, moves the rendered tick (<code>.dropdown-item__check</code>), and closes the menu.</li><li><strong>Double click</strong> a row name → inline rename: overlays a <code>.filter-bar-v1__rename</code> <code>&lt;input&gt;</code> on the row (Enter / blur commits, Escape cancels; committing the current view also updates the trigger).</li><li><strong>&quot;Rename&quot; in the row&#39;s … menu</strong> (<code>[data-filter-rename]</code>, alongside Copy / Delete) is the touch-friendly equivalent — it runs the same inline rename. The … menu is now present on <strong>every</strong> row including the selected one, so any view can be renamed/copied/deleted. (Double-click stays as a desktop shortcut.)</li></ul><p>Mobile/touch: the per-row … is hover-revealed on desktop but <strong>always visible on touch</strong> (<code>@media (hover: none)</code> in <code>Dropdown.css</code>) so Rename/Copy/Delete are reachable without hover.</p><p>On the <strong>selected</strong> row the … overlays the trailing tick, so the tick is hidden whenever the … is shown — row <code>:hover</code>, its menu open (<code>:has([aria-expanded=&quot;true&quot;])</code>), or always on touch (scoped to <code>.filter-bar-v1__views</code>, since only the FilterBar puts a … on the selected row).</p><p>Because single-click on a <code>.dropdown-item</code> normally closes the panel (Dropdown.js), row clicks are intercepted in the <strong>capture phase</strong> with <code>stopPropagation</code>, and a ~220ms timer disambiguates single vs double click. The rename <code>&lt;input&gt;</code> is appended to the <code>&lt;li&gt;</code> (it can&#39;t nest inside the row&#39;s <code>&lt;button&gt;</code>) with the <code>&lt;li&gt;</code> made <code>position: relative</code> via <code>.filter-bar-v1__li--renaming</code>. <strong>This rename interaction is code-first — not in the Figma spec; flag for designer review.</strong></p><p>Two structural rules this relies on:</p><ul><li><strong><code>.filter-bar-v1__search</code> is a sibling of <code>__main</code>, not a child</strong> — search mode hides <code>__main</code> (<code>display:none</code>), so a search field nested inside it would be hidden too. It lives as a direct child of the root.</li><li><strong>The kebab menu&#39;s <code>.dropdown__panel</code> is right-aligned</strong> (<code>left:auto; right:0</code>) since the kebab sits at the far-right edge; the default <code>left:0</code> would overflow.</li></ul><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Class</th><th>Notes</th></tr></thead><tbody><tr><td>Root</td><td><code>.filter-bar-v1</code></td><td>bg surface-primary, border-secondary, radius-md, pad 12/16/12/12, gap 16</td></tr><tr><td>Main group</td><td><code>.filter-bar-v1__main</code></td><td>flex-1, gap 8; <code>display: contents</code> on mobile</td></tr><tr><td>Saved-views control</td><td><code>.dropdown.filter-bar-v1__views</code></td><td>composes Dropdown (filter-views panel)</td></tr><tr><td>Views trigger</td><td><code>.dropdown__trigger.filter-bar-v1__views-trigger</code></td><td>field-styled: w <code>--ai-size-3</code> (192), h <code>--ai-spacing-8</code> (40), px <code>--ai-spacing-5</code>, 14px <strong>medium</strong></td></tr><tr><td>Chips group</td><td><code>.filter-bar-v1__chips</code></td><td>flex-wrap, gap 8, left divider; chips are FilterItem <strong><code>--empty</code></strong> (dashed) in V1</td></tr><tr><td>Actions</td><td><code>.filter-bar-v1__actions</code></td><td>search icon-btn + kebab <code>.dropdown</code></td></tr><tr><td>Icon button</td><td><code>.filter-bar-v1__icon-btn</code></td><td>bare 16px icon, <code>--ai-icon-contrast</code></td></tr><tr><td>Search field</td><td><code>.filter-bar-v1__search</code></td><td>composes Input (leading search icon)</td></tr><tr><td>New-view field</td><td><code>.filter-bar-v1__new-view</code></td><td>composes Input (value + <code>.input__clear</code>)</td></tr><tr><td>Create</td><td><code>.btn.btn--primary.filter-bar-v1__create</code></td><td>composes Button</td></tr><tr><td>Save view CTA</td><td><code>.btn.btn--primary.btn--sm.filter-bar-v1__save</code></td><td>composes Button (primary, sm); hidden until <code>.filter-bar-v1--save-view</code></td></tr><tr><td>Back</td><td><code>.filter-bar-v1__back</code></td><td>search-mode only, <code>arrow-left</code></td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>Token</th><th>Role</th></tr></thead><tbody><tr><td>surface/primary</td><td><code>--ai-surface-primary</code></td><td>bar + field bg</td></tr><tr><td>border/secondary</td><td><code>--ai-border-secondary</code></td><td>bar border, field border, chip divider</td></tr><tr><td>spacing/5 (16)</td><td><code>--ai-spacing-5</code></td><td>bar gap, field px, bar pr</td></tr><tr><td>spacing/4 (12)</td><td><code>--ai-spacing-4</code></td><td>bar py, bar pl, mobile gap</td></tr><tr><td>spacing/3 (8)</td><td><code>--ai-spacing-3</code></td><td>main/chips/actions gap, chip-group pl</td></tr><tr><td>spacing/8 (40)</td><td><code>--ai-spacing-8</code></td><td>views/field height</td></tr><tr><td>size/3 (192)</td><td><code>--ai-size-3</code></td><td>views trigger + new-view width</td></tr><tr><td>radius/md (8)</td><td><code>--ai-radius-md</code></td><td>bar + fields</td></tr><tr><td>font/body, fixed-xs (14), medium, leading-md (24)</td><td><code>--ai-font-body</code> / <code>--ai-font-fixed-xs</code> / <code>--ai-font-medium</code> / <code>--ai-leading-md</code></td><td>views trigger text</td></tr><tr><td>icon/contrast</td><td><code>--ai-icon-contrast</code></td><td>search / kebab / chevron / back icons</td></tr><tr><td>icon-size/sm (16)</td><td><code>--ai-icon-size-sm</code></td><td>those icons</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None for the toolbar shell. <strong>One Figma artifact documented, not reproduced:</strong> the &quot;Add Filters&quot; chip in some variants is a detached <strong>&quot;MinimalBadge&quot;</strong> layer whose label uses the raw hex <code>#364153</code> (Gray/700, no <code>--ai-*</code> token). The DS-correct element is a <strong>FilterItem in the Empty state</strong> (label <code>--ai-text-primary</code>), which is what this build composes — the raw hex is not carried over. Flagged for the designer to replace the detached layer with a proper Filter Item instance.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Views trigger is a Dropdown, not a Select.</strong> Figma renders it as a field (<code>data-name=&quot;Input&quot;</code>), but the menu is the rich saved-views panel (label + radio rows + per-row Copy/Delete mini-menu + &quot;New view&quot;), which only the <strong>Dropdown</strong> &quot;filter-views&quot; variant provides. So the trigger is a field-styled <code>.dropdown__trigger</code> and the panel reuses <code>.dropdown__panel--filter-views</code>.</li><li><strong>Search field full-width.</strong> Figma reports the search Input at the component&#39;s base <code>w-192</code>, but the screenshot (and the search scenario&#39;s intent) is a full-width field — built as <code>flex: 1</code>.</li><li><strong>No Figma hover/focus</strong> for the bare icons or the field trigger; <code>:focus-visible</code> rings added for WCAG 2.1 AA only.</li><li><strong>Width is consumer-controlled</strong> (fills its container). Figma&#39;s 960px frame is <code>--ai-size-12</code> (a canvas width, not a component constraint).</li></ul><h2 id="backend-handover" tabindex="-1">Backend handover <a class="header-anchor" href="#backend-handover" aria-label="Permalink to &quot;Backend handover&quot;">​</a></h2><p><code>TODO(backend:Filters)</code> — saved-views list, value pickers, search querying, Create (persist a new view), Export, and the kebab actions are all mock. See <code>HANDOVER.md</code> → Surface: Filters.</p><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li><strong>Dropdown</strong> (<code>src/components/Dropdown/</code>) — saved-views (<code>--filter-views</code>) panel + kebab actions menu; brings DropdownItem.</li><li><strong>FilterItem</strong> (<code>src/components/FilterItem/</code>) — the chips (V1 uses <code>--empty</code>).</li><li><strong>Input</strong> (<code>src/components/Input/</code>) — search + new-view fields.</li><li><strong>Button</strong> (<code>src/components/Button/</code>) — Create (<code>--primary</code>), and the tertiary buttons inside the dropdowns.</li><li>Lucide icons: <code>chevron-down</code>, <code>search</code>, <code>ellipsis-vertical</code>, <code>arrow-left</code>, <code>plus</code>, <code>x</code>, <code>check</code>, <code>ellipsis</code>, <code>copy</code>, <code>trash-2</code>.</li></ul>',32)])])}const u=t(i,[["render",a]]);export{g as __pageData,u as default};
